customMethods.script:
toolMeta = BlueRidge.Parts.Tool.getOne(toolId)
if toolMeta is None:
	BlueRidge.Common.Notify.toast('Tool not found', 'Tool id ' + str(toolId) + ' no longer exists.', 'warning')
	return
self.view.custom.selected  = {'meta': dict(toolMeta)}
self.view.custom.editDraft = {'meta': dict(toolMeta)}
self.view.custom.mode = 'update'

# True when the meta header has unsaved edits OR any draft section is dirty.
if self.view.custom.dirty:
	return True
sectionMap = self.view.custom.sectionDirty or {}
return any(sectionMap.values())

system.perspective.openPopup(
	id='mpp-confirm-unsaved',
	view='BlueRidge/Components/Popups/ConfirmUnsaved',
	modal=True,
	showCloseIcon=False,
	params={
		'title':   'Unsaved changes',
		'message': 'You have unsaved changes to this tool. Save before switching?'
	}
)

pending = self.view.custom.pendingSwitch or {}
kind   = pending.get('kind')
target = pending.get('to')
self.view.custom.pendingSwitch = None
if kind == 'tab':
	sectionKeys = ['attributes', 'cavities', 'assignments']
	self.view.custom.activeTabIndex = target
	if target is not None and 0 <= target < len(sectionKeys):
		self.view.custom.activeTab = sectionKeys[target]
elif kind == 'tool':
	self._loadTool(target)

messageHandlers.script:
action = payload.get('action') if payload else None
pending = self.view.custom.pendingSwitch
if not pending:
	return
if action == 'cancel':
	self.cancelSwitch()
	return
sectionMap = dict(self.view.custom.sectionDirty or {})
dirtySections = [k for k, v in sectionMap.items() if v]
metaDirty = bool(self.view.custom.dirty)
if action == 'save':
	if metaDirty:
		draft = self.view.custom.editDraft or {}
		meta  = draft.get('meta') or {}
		if meta.get('Id') is not None:
			result = BlueRidge.Parts.Tool.update(meta)
			BlueRidge.Common.Ui.notifyResult(result, 'Tool saved')
			if result and result.get('Status'):
				refreshed = BlueRidge.Parts.Tool.getOne(meta.get('Id'))
				if refreshed is not None:
					self.view.custom.selected  = {'meta': dict(refreshed)}
					self.view.custom.editDraft = {'meta': dict(refreshed)}
			system.perspective.sendMessage('toolRefresh', scope='page')
	for sec in dirtySections:
		system.perspective.sendMessage('sectionSaveRequested', payload={'section': sec}, scope='page')
elif action == 'discard':
	if metaDirty:
		self.view.custom.editDraft = {'meta': dict((self.view.custom.selected or {}).get('meta') or {})}
	for sec in dirtySections:
		system.perspective.sendMessage('sectionDiscardRequested', payload={'section': sec}, scope='page')
# If no draft sections were dirty, the section-clean callback never
# fires -- complete the switch now that the meta leg is resolved.
if not dirtySections:
	self.completeSwitch()

action = payload.get('action') if payload else None
if action != 'confirm':
	return
meta = (self.view.custom.selected or {}).get('meta') or {}
toolId = meta.get('Id')
if toolId is None:
	return
result = BlueRidge.Parts.Tool.deprecate(toolId)
BlueRidge.Common.Ui.notifyResult(result, 'Tool retired')
if result and result.get('Status'):
	self.view.custom.selected  = {'meta': None}
	self.view.custom.editDraft = {'meta': None}
	self.view.custom.mode = 'view'
	system.perspective.sendMessage('toolRefresh', scope='page')

config.script:
draft = self.view.custom.editDraft or {}
meta  = draft.get('meta') or {}
if meta.get('Id') is None:
	BlueRidge.Common.Notify.toast('No tool selected', 'Pick a tool from the list first.', 'warning')
	return
result = BlueRidge.Parts.Tool.update(meta)
BlueRidge.Common.Ui.notifyResult(result, 'Tool saved')
if result and result.get('Status'):
	refreshed = BlueRidge.Parts.Tool.getOne(meta.get('Id'))
	if refreshed is not None:
		self.view.custom.selected  = {'meta': dict(refreshed)}
		self.view.custom.editDraft = {'meta': dict(refreshed)}
	system.perspective.sendMessage('toolRefresh', scope='page')
